+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import { getEntityId } from '../../entity/utils/pack-entity';
+import { isRelation } from '../../relation/utils/is-relation';
+import { getTrait, hasTrait } from '../../trait/trait';
+import type { Trait, TraitInstance } from '../../trait/types';
+import type { World } from '../../world';
+import { createModifier } from '../modifier';
+import { addEntityToQuery, removeEntityFromQuery } from '../query';
+import type { EventType, Predicate, PredicateData, PredicateTrackingModifier, QueryInstance } from '../types';
+import { checkQueryWithRelations } from '../utils/check-query-with-relations';
+
+let predicateId = 0;
+
+export function createPredicate<T extends Trait[]>(
+    traits: T,
+    predicate: (data: PredicateData<T>) => boolean
+): Predicate<T> {
+    for (const trait of traits) {
+        if (trait[$internal].type === 'tag' || isRelation(trait)) {
+            throw new Error('Koota: Predicate dependencies must be data traits, not tags or relations.');
+        }
+    }
+
+    const modifier = createModifier('predicate', predicateId++, traits) as Predicate<T>;
+    modifier.predicate = predicate;
+    return modifier;
+}
+
+export function createPredicateTrackingModifier<T extends Trait[]>(
+    type: EventType,
+    id: number,
+    predicate: Predicate<T>
+): PredicateTrackingModifier<T> {
+    const modifier = createModifier(`${type}-predicate-${id}`, id, predicate.traits) as PredicateTrackingModifier<T>;
+    modifier.predicate = predicate.predicate;
+    return modifier;
+}
+
+export function isPredicateModifier(modifier: { predicate?: unknown }): modifier is Predicate {
+    return typeof modifier.predicate === 'function' && modifier.type === 'predicate';
+}
+
+export function isPredicateTrackingModifier(
+    modifier: { predicate?: unknown; type: string }
+): modifier is PredicateTrackingModifier {
+    return typeof modifier.predicate === 'function' && modifier.type.includes('-predicate-');
+}
+
+export function matchesPredicate(world: World, entity: Entity, predicate: Predicate): boolean {
+    const data: unknown[] = [];
+    for (const trait of predicate.traits) {
+        if (!hasTrait(world, entity, trait)) return false;
+        data.push(getTrait(world, entity, trait));
+    }
+    return predicate.predicate(data as PredicateData<Trait[]>);
+}
+
+export function reevaluatePredicateQueries(world: World, entity: Entity, instance: TraitInstance) {
+    for (const query of instance.predicateQueries) {
+        const staticMatch = checkQueryWithRelations(world, query, entity);
+        if (staticMatch) addEntityToQuery(query, entity);
+        else removeEntityFromQuery(world, query, entity);
+
+        for (const predicate of query.predicateTracking) {
+            const eid = getEntityId(entity);
+            const states = query.predicateTrackingStates.get(predicate.id)!;
+            const previous = states[eid] ?? matchesPredicate(world, entity, predicate);
+            const current = matchesPredicate(world, entity, predicate);
+            states[eid] = current;
+
+            const event = predicate.type.startsWith('add')
+                ? !previous && current
+                : predicate.type.startsWith('remove')
+                  ? previous && !current
+                  : previous !== current;
+            if (event && staticMatch) addEntityToQuery(query, entity);
+            else if (!event) removeEntityFromQuery(world, query, entity);
+        }
+    }
+}
